mapper.select:
/* ShopAuthMapper.getCommonCodeName: 공통코드 코드명 조회 */
SELECT CD_NM
  FROM COMMON_CODE
 WHERE GRP_CD = #{grpCd}
   AND CD = #{cd}
 LIMIT 1

mapper.insert:
/* ShopAuthMapper.insertShopGoogleCustomer: 구글 신규 회원 정보를 등록 */
INSERT INTO CUSTOMER_BASE (
       LOGIN_ID
     , PASSWORD
     , CUST_NM
     , CUST_GRADE_CD
     , CUST_STAT_CD
     , JOIN_GB
     , SEX
     , BIRTH
     , PHONE_NUMBER
     , EMAIL
     , SMS_RSV_YN
     , SMS_RSV_DT
     , EMAIL_RSV_YN
     , EMAIL_RSV_DT
     , APP_PUSH_RSV_YN
     , APP_PUSH_RSV_DT
     , DEVICE_GB_CD
     , CI
     , DI
     , REG_NO
     , UDT_NO
) VALUES (
       #{command.loginId}
     , #{command.password}
     , #{command.custNm}
     , #{command.custGradeCd}
     , #{command.custStatCd}
     , #{command.joinGb}
     , #{command.sex}
     , #{command.birth}
     , #{command.phoneNumber}
     , #{command.email}
     , #{command.smsRsvYn}
     , CASE WHEN #{command.smsRsvYn} = 'Y' THEN NOW() ELSE NULL END
     , #{command.emailRsvYn}
     , CASE WHEN #{command.emailRsvYn} = 'Y' THEN NOW() ELSE NULL END
     , #{command.appPushRsvYn}
     , CASE WHEN #{command.appPushRsvYn} = 'Y' THEN NOW() ELSE NULL END
     , #{command.deviceGbCd}
     , #{command.ci}
     , #{command.di}
     , #{command.regNo}
     , #{command.udtNo}
)

mapper.update:
/* ShopAuthMapper.updateShopGoogleCustomerAuditNo: 구글 신규 회원 등록 후 REG_NO/UDT_NO를 고객번호로 갱신 */
UPDATE CUSTOMER_BASE
   SET REG_NO = #{auditNo}
     , UDT_NO = #{auditNo}
 WHERE CUST_NO = #{custNo}

mapper.select:
/* ShopAuthMapper.getShopJoinPoint: 사이트 회원가입 기본 포인트 조회 */
SELECT JOIN_POINT
  FROM SITE_INFO
 WHERE SITE_ID = #{siteId}
 LIMIT 1

mapper.insert:
/* ShopAuthMapper.insertCustomerPointBase: 회원가입 포인트 마스터 이력을 등록 */
INSERT INTO CUSTOMER_POINT_BASE (
       CUST_NO
     , PNT_GIVE_GB_CD
     , PNT_GIVE_MEMO
     , SAVE_AMT
     , USE_AMT
     , RMN_AMT
     , REG_NO
     , UDT_NO
) VALUES (
       #{command.custNo}
     , #{command.pntGiveGbCd}
     , #{command.pntGiveMemo}
     , #{command.saveAmt}
     , 0
     , #{command.saveAmt}
     , #{command.regNo}
     , #{command.udtNo}
)

/* ShopAuthMapper.insertCustomerPointDetail: 회원가입 포인트 상세 이력을 등록 */
INSERT INTO CUSTOMER_POINT_DETAIL (
       PNT_NO
     , PNT_AMT
     , BIGO
     , REG_NO
) VALUES (
       #{command.pntNo}
     , #{command.pntAmt}
     , #{command.bigo}
     , #{command.regNo}
)

/* ShopAuthMapper.insertCustomerCoupon: 고객에게 쿠폰 1건을 지급 등록 */
INSERT INTO CUSTOMER_COUPON (
       CUST_NO
     , CPN_NO
     , CPN_USABLE_START_DT
     , CPN_USABLE_END_DT
     , CPN_USE_YN
     , REG_NO
     , UDT_NO
) VALUES (
       #{command.custNo}
     , #{command.cpnNo}
     , #{command.cpnUsableStartDt}
     , #{command.cpnUsableEndDt}
     , 'N'
     , #{command.regNo}
     , #{command.udtNo}
)
